svg.script:
const full = "mozzarella();";
const text = document.getElementById("text");
const shine = document.getElementById("shine");
const cursor = document.getElementById("cursor");
const line = document.getElementById("line");

const startX = 100;
const charW = 72;

let i = 0;
let del = false;

function render() {
  const shown = full.slice(0, i);
  text.textContent = shown;
  shine.textContent = shown;
  const w = shown.length * charW;
  cursor.setAttribute("x", startX + w + 5);
  line.setAttribute("width", w + 5);
}

function loop() {
  render();

  if (!del && i < full.length) {
    i++;
    setTimeout(loop, 80);
    return;
  }

  if (!del && i === full.length) {
    del = true;
    setTimeout(loop, 1200);
    return;
  }

  if (del && i > 0) {
    i--;
    setTimeout(loop, 40);
    return;
  }

  if (del && i === 0) {
    del = false;
    setTimeout(loop, 300);
  }
}

const blink = () => {
  let on = true;
  setInterval(() => {
    cursor.setAttribute("opacity", on ? "1" : "0.2");
    on = !on;
  }, 350);
};

blink();
loop();
